Below is a minimal example of a Pokémon NFT smart contract in Solidity that follows the Product Requirements Document (PRD). It includes:

• ERC721 functionality using OpenZeppelin  
• Role-based access for admin minting (special cards)  
• A daily pack opening that enforces a 24-hour cooldown per user  
• Basic pseudo-random rarity distribution  

The code is highly commented so you can follow along even if you’re new to Solidity. Feel free to customize it (add more metadata, change the random logic, etc.) to meet your needs.

--------------------------------------------------------------------------------
1. Solidity File: contracts/PokemonNFT.sol
--------------------------------------------------------------------------------

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.17;

/**
 * @title PokemonNFT
 * @dev Example of a Pokémon NFT contract that uses ERC721 with role-based minting
 *      and daily pack opening. This contract demonstrates how to store metadata
 *      on-chain, enforce a 24-hour mint cooldown, and distribute rarity based
 *      on a simple pseudo-random function.
 */

import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Counters.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract PokemonNFT is ERC721URIStorage, AccessControl, ReentrancyGuard {
    using Counters for Counters.Counter;

    // ========== ROLES & CONSTANTS ==========

    /// @notice Role identifier for accounts that can mint special (rare) cards
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");

    /// @dev Used to ensure a user can only open a daily pack once every 24 hours
    uint256 public constant DAY_IN_SECONDS = 86400;

    // ========== STATE VARIABLES ==========

    Counters.Counter private _tokenIds;

    /// @notice Tracks the last timestamp a user opened a daily pack
    mapping(address => uint256) public lastOpenedTimestamp;

    /// @dev A mapping from tokenId => CardMetadata (on-chain storage of attributes)
    mapping(uint256 => CardMetadata) public cardMetadata;

    // ========== DATA STRUCTURES ==========

    /**
     * @dev Struct to hold important Pokémon card attributes.
     *      This is just an example; adapt fields to your app's needs.
     */
    struct CardMetadata {
        string name;             // e.g. "Charizard VMAX"
        string cardType;         // e.g. "Fire"
        string evolutionStage;   // e.g. "V/VMAX/VSTAR"
        string weakness;         // e.g. "Water x2"
        string resistance;       // e.g. "Fighting -30"
        string ability;          // e.g. "Battle Sense: Draw 3 cards."
        string attack;           // e.g. "G-Max Wildfire: 120 damage"
        string rarity;           // e.g. "Common", "Uncommon", "Rare", "Ultra Rare"
        uint256 hp;             // e.g. 330
    }

    // ========== EVENTS ==========

    /// @dev Emitted when a new card is minted
    event CardMinted(
        uint256 indexed tokenId,
        address indexed owner,
        string rarity
    );

    // ========== CONSTRUCTOR ==========

    /**
     * @param _name   Collection name (e.g. "PokemonNFTCollection")
     * @param _symbol Collection symbol (e.g. "PKMN")
     */
    constructor(string memory _name, string memory _symbol)
        ERC721(_name, _symbol)
    {
        // Grant the deployer the default admin role and the minter role
        _setupRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _setupRole(MINTER_ROLE, msg.sender);
    }

    // ========== EXTERNAL / PUBLIC FUNCTIONS ==========

    /**
     * @notice Allows an authorized minter to mint special (rare) Pokémon cards.
     *         Useful for promotional events, giveaways, or manual minting.
     * @param to      The address that will receive the NFT
     * @param data    The on-chain metadata for this card
     * @param tokenURI_  IPFS or other URI pointing to off-chain metadata if desired,
     *                   or you can leave it empty if you only need on-chain data.
     */
    function mintRareCard(
        address to,
        CardMetadata calldata data,
        string calldata tokenURI_
    )
        external
        onlyRole(MINTER_ROLE)
        nonReentrant
    {
        _tokenIds.increment();
        uint256 newTokenId = _tokenIds.current();

        // Mint the token
        _safeMint(to, newTokenId);
        // Store the card metadata on-chain
        cardMetadata[newTokenId] = data;
        // If you have a URI (e.g. IPFS metadata file), you can set it here
        _setTokenURI(newTokenId, tokenURI_);

        emit CardMinted(newTokenId, to, data.rarity);
    }

    /**
     * @notice Allows any user to open a "Daily Pack" once every 24 hours to mint a new card.
     */
    function openDailyPack() external nonReentrant {
        require(
            block.timestamp >= lastOpenedTimestamp[msg.sender] + DAY_IN_SECONDS,
            "You must wait 24 hours to open another pack"
        );

        lastOpenedTimestamp[msg.sender] = block.timestamp;

        // 1. Determine rarity
        string memory rarity = _getRandomRarity();

        // 2. Create some sample data; in a real-world app, you might fetch
        //    random Pokémon data from an off-chain source or generate different stats.
        CardMetadata memory newCard = CardMetadata({
            name: "Random Pokémon",
            cardType: "Unknown",
            evolutionStage: "Basic",
            weakness: "None",
            resistance: "None",
            ability: "None",
            attack: "Tackle",
            rarity: rarity,
            hp: 100
        });

        // 3. Mint the card
        _tokenIds.increment();
        uint256 newTokenId = _tokenIds.current();
        _safeMint(msg.sender, newTokenId);

        // 4. Store the new card’s metadata on-chain
        cardMetadata[newTokenId] = newCard;

        // 5. (Optional) If you want to store off-chain metadata, call _setTokenURI()
        //    e.g. _setTokenURI(newTokenId, "ipfs://...metadata.json");

        emit CardMinted(newTokenId, msg.sender, rarity);
    }

    // ========== READ-ONLY FUNCTIONS ==========

    /**
     * @notice Get the CardMetadata for a given tokenId.
     * @param tokenId The ID of the token to fetch metadata for.
     */
    function getCardMetadata(uint256 tokenId)
        external
        view
        returns (CardMetadata memory)
    {
        require(_exists(tokenId), "Token does not exist");
        return cardMetadata[tokenId];
    }

    // ========== INTERNAL & PRIVATE HELPERS ==========

    /**
     * @dev A very naive pseudo-random approach to determine the rarity of a card.
     *      For production apps, consider using Chainlink VRF or commit-reveal schemes.
     */
    function _getRandomRarity() internal view returns (string memory) {
        // 1. Create a random value out of 100
        uint256 randomNum = uint256(
            keccak256(
                abi.encodePacked(
                    block.timestamp,
                    block.prevrandao,     // prevrandao is recommended over blockhash in >=0.8.18
                    msg.sender
                )
            )
        ) % 100;

        // 2. Distribute rarity:
        //   50% Common, 30% Uncommon, 15% Rare, 5% Ultra Rare
        if (randomNum < 50) {
            return "Common";
        } else if (randomNum < 80) {
            return "Uncommon";
        } else if (randomNum < 95) {
            return "Rare";
        } else {
            return "Ultra Rare";
        }
    }
}

--------------------------------------------------------------------------------
2. Explanation of Key Parts
--------------------------------------------------------------------------------

1) Inheritance:
   • ERC721URIStorage – Lets us store and update metadata URIs for each token.  
   • AccessControl – Provides role-based permissioning.  
   • ReentrancyGuard – Helps prevent reentrancy attacks in state-changing functions.  

2) Roles:
   • MINTER_ROLE – Addresses with this role can call special mint functions like mintRareCard().  
   • DEFAULT_ADMIN_ROLE – The contract deployer is given this role by default and can grant/revoke other roles.  

3) Storing Metadata:
   • We define a struct CardMetadata to keep all card attributes on-chain.  
   • The mapping(uint256 => CardMetadata) public cardMetadata holds each token’s metadata.  

4) Daily Pack:
   • We track the lastOpenedTimestamp for each user. They must wait 24 hours (86400 seconds) before calling openDailyPack() again.  
   • A random rarity is assigned via _getRandomRarity(), which uses a simple pseudo-random technique.  
   • A new NFT token is minted and assigned to the caller.  

5) Rarity Calculation:
   • The contract generates a random number from 0 to 99.  
   • Rarity distribution is: 50% Common, 30% Uncommon, 15% Rare, 5% Ultra Rare.  
   • In production, a more secure random approach (e.g. Chainlink VRF) is recommended.  

6) Token URI:
   • If you want to store your metadata off-chain (e.g., on IPFS), generate a JSON file that conforms to ERC721 metadata standards, upload it to IPFS, and call _setTokenURI(tokenId, "ipfs://...") inside your mint function.  
   • Because we also store data on-chain in cardMetadata, the off-chain URI is optional or can be used for your NFT image references.  

--------------------------------------------------------------------------------
3. Next Steps
--------------------------------------------------------------------------------

• Set up your Hardhat project structure (contracts, scripts, tests, etc.).  
• Run npx hardhat compile to ensure the contract compiles.  
• Write deploy scripts to deploy PokemonNFT.  
• Implement the Marketplace contract (for trading, listing, buying) as described in the PRD.  
• Connect your Next.js (TypeScript) front end with this contract using Wagmi & Viem.  
  - Show users their NFTs, let them open a daily pack, and (in the future) list items for sale.  
• Consider using IPFS + Pinata for your Pokémon card images.  

--------------------------------------------------------------------------------
With this foundation, you have a working Pokémon NFT contract that supports both admin-managed minting (for rare/special cards) and user minting via “Daily Packs.” Next, you can focus on building out the marketplace and front end to complete your decentralized Pokémon card trading platform. Happy coding!
