2. Example Usage in Your Contract
--------------------------------------------------------------------------------

Below is how you might incorporate these updated structs into your Pokémon NFT contract. For brevity, we only illustrate the relevant metadata changes and how you’d populate them in mint functions.

pragma solidity ^0.8.17;

import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Counters.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

// Define your structs outside the contract or within, up to you
struct Attack {
    string name;
    uint256 damage;
    string[] energyCost;
    string effect;
}

struct Weakness {
    string typeOf;
    uint256 multiplier; // e.g. 2 means "x2"
}

struct Resistance {
    string typeOf;
    int256 reduction; // e.g. -30
}

struct Ability {
    string name;
    string description;
}

struct CardMetadata {
    string name;
    string cardType;
    string evolutionStage;
    Weakness[] weaknesses;
    Resistance[] resistances;
    Ability[] abilities;
    Attack[] attacks;
    string rarity;
    uint256 hp;
}

contract PokemonNFT is ERC721URIStorage, AccessControl, ReentrancyGuard {
    using Counters for Counters.Counter;

    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");

    Counters.Counter private _tokenIds;

    // Map tokenId => CardMetadata
    mapping(uint256 => CardMetadata) public cardMetadata;

    constructor(string memory _name, string memory _symbol)
        ERC721(_name, _symbol)
    {
        _setupRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _setupRole(MINTER_ROLE, msg.sender);
    }

    event CardMinted(uint256 indexed tokenId, address indexed owner, string rarity);

    /**
     * @notice Example function to mint with more complex metadata:
     *         Accept arrays and nested structs as parameters.
     */
    function mintComplexCard(
        address to,
        // Basic fields
        string memory _name,
        string memory _cardType,
        string memory _evolutionStage,
        string memory _rarity,
        uint256 _hp,
        // Arrays of struct fields
        Weakness[] memory _weaknesses,
        Resistance[] memory _resistances,
        Ability[] memory _abilities,
        Attack[] memory _attacks,
        // Optional URI
        string memory _tokenURI
    ) external onlyRole(MINTER_ROLE) nonReentrant {
        _tokenIds.increment();
        uint256 newTokenId = _tokenIds.current();

        // Mint the NFT
        _safeMint(to, newTokenId);

        // Store the nested struct data in memory -> storage
        CardMetadata storage newCard = cardMetadata[newTokenId];
        newCard.name = _name;
        newCard.cardType = _cardType;
        newCard.evolutionStage = _evolutionStage;
        newCard.rarity = _rarity;
        newCard.hp = _hp;

        // Copy weaknesses from memory array to storage array
        for (uint256 i = 0; i < _weaknesses.length; i++) {
            newCard.weaknesses.push(
                Weakness({
                    typeOf: _weaknesses[i].typeOf,
                    multiplier: _weaknesses[i].multiplier
                })
            );
        }

        // Copy resistances from memory array to storage array
        for (uint256 i = 0; i < _resistances.length; i++) {
            newCard.resistances.push(
                Resistance({
                    typeOf: _resistances[i].typeOf,
                    reduction: _resistances[i].reduction
                })
            );
        }

        // Copy abilities from memory array to storage array
        for (uint256 i = 0; i < _abilities.length; i++) {
            newCard.abilities.push(
                Ability({
                    name: _abilities[i].name,
                    description: _abilities[i].description
                })
            );
        }

        // Copy attacks from memory array to storage array
        for (uint256 i = 0; i < _attacks.length; i++) {
            Attack memory attackMem = _attacks[i];
            // energyCost is itself an array of strings, so we also need to copy it carefully
            // Easiest approach: push a new Attack struct with a freshly allocated array for energyCost
            string[] memory energyCostArray = new string[](attackMem.energyCost.length);
            for (uint256 j = 0; j < attackMem.energyCost.length; j++) {
                energyCostArray[j] = attackMem.energyCost[j];
            }

            newCard.attacks.push(
                Attack({
                    name: attackMem.name,
                    damage: attackMem.damage,
                    energyCost: energyCostArray,
                    effect: attackMem.effect
                })
            );
        }

        // Optionally set a tokenURI for off-chain metadata or images
        _setTokenURI(newTokenId, _tokenURI);

        emit CardMinted(newTokenId, to, _rarity);
    }

    // Example of how to retrieve the stored data (abilities, attacks, etc.)
    function getCardMetadata(uint256 tokenId)
        external
        view
        returns (CardMetadata memory)
    {
        require(_exists(tokenId), "Token does not exist");
        return cardMetadata[tokenId];
    }
}

--------------------------------------------------------------------------------
3. Points to Consider
--------------------------------------------------------------------------------

1) Gas Costs
   • Nesting dynamic arrays (e.g., string[]) in structs can be very expensive.  
   • If your contract expects to store a lot of data for many NFTs, reconsider storing it all on-chain.  
   • A common pattern is to store the “bare minimum” on-chain (like a single metadata URI) and keep full details in an off-chain JSON on IPFS.

2) Copying Arrays
   • When you pass dynamic arrays (like string[] or Attack[]), you can’t simply assign them to a storage array. You must manually copy them, as shown in the example.  
   • This is because storage and memory in Solidity are handled differently.

3) Retrieving Custom Structs
   • Returning a struct that contains nested arrays is allowed in Solidity, but if you intend to do so often, it can be expensive. If performance is critical, reduce complexity or store static keys that your frontend can fetch from IPFS.

4) Off-Chain Metadata
   • Often, NFT contracts store just a “tokenURI” pointing to IPFS, and the JSON metadata (including arrays, nested fields, etc.) lives entirely off-chain. This is typically far cheaper and more flexible.  
   • If you need complete on-chain verification / immutability, then carefully plan your data layout to minimize gas usage.

5) Use Library or Off-Chain Parsing
   • Another advanced approach is to store a single bytes data field (e.g., a serialized JSON or bytes-encoded struct) on-chain, and decode it off-chain with your front end. This can be more space-efficient than storing a lot of strings.

--------------------------------------------------------------------------------
Conclusion
--------------------------------------------------------------------------------
By using nested structs and dynamic arrays (e.g., Attack[]), you can create very detailed on-chain metadata. Always weigh the trade-offs between gas costs and the complexity of storing large data structures. If your NFTs require very rich metadata, you may consider storing only essential info on-chain (for authenticity / ownership checks) with a pointer to an IPFS JSON for the rest of the content.
What is this error:
solidity: Derived contract must override function "supportsInterface". Two or more base classes define function with same name and parameter types.
This error occurs because your contract inherits from multiple parent classes (for example, ERC721 and AccessControl from OpenZeppelin), each of which implements the function “supportsInterface”. When multiple base contracts define the same function signature, Solidity requires you to explicitly override that function in your derived (child) contract so it knows which implementation to use (or how to combine them).

─────────────────────────────────────────────────────────────────
Why It Happens
─────────────────────────────────────────────────────────────────
• Both ERC721 and AccessControl (from OpenZeppelin) extend ERC165, which defines supportsInterface.  
• When your child contract inherits from both, Solidity sees two potential implementations of supportsInterface and requires you to resolve the conflict with an explicit override.

─────────────────────────────────────────────────────────────────
How To Fix It
─────────────────────────────────────────────────────────────────
Simply add an override in your child contract specifying which parent contracts you are overriding and how to handle the final logic. For example:

function supportsInterface(bytes4 interfaceId) 
    public 
    view 
    virtual 
    override(ERC721, AccessControl) 
    returns (bool) 
{
    // Combine multiple super calls if needed or just choose one
    // Usually, we unify them by forwarding to super and letting OpenZeppelin handle it
    return super.supportsInterface(interfaceId);
}

